import{_ as a,o as e,c as l,ag as i}from"./chunks/framework.DEqXEGcv.js";const p=JSON.parse('{"title":"桌面环境","description":"","frontmatter":{},"headers":[],"relativePath":"zh/docs/guide/desktop.md","filePath":"zh/docs/guide/desktop.md"}'),r={name:"zh/docs/guide/desktop.md"};function o(d,t,n,s,h,u){return e(),l("div",null,[...t[0]||(t[0]=[i('<h1 id="桌面环境" tabindex="-1">桌面环境 <a class="header-anchor" href="#桌面环境" aria-label="Permalink to &quot;桌面环境&quot;">​</a></h1><p>RDE 提供类 Windows 的 Web 桌面体验，在浏览器中即可获得完整的桌面操作环境。</p><h2 id="窗口管理器" tabindex="-1">窗口管理器 <a class="header-anchor" href="#窗口管理器" aria-label="Permalink to &quot;窗口管理器&quot;">​</a></h2><p>窗口管理器是 RDE 桌面的核心组件，管理所有应用窗口的生命周期、布局和交互。</p><h3 id="窗口操作" tabindex="-1">窗口操作 <a class="header-anchor" href="#窗口操作" aria-label="Permalink to &quot;窗口操作&quot;">​</a></h3><ul><li><strong>拖拽移动</strong>：按住标题栏拖拽窗口到任意位置</li><li><strong>缩放大小</strong>：拖拽窗口边缘调整大小</li><li><strong>最大化</strong>：双击标题栏或点击最大化按钮</li><li><strong>最小化</strong>：点击最小化按钮，窗口收纳到任务栏</li><li><strong>关闭</strong>：点击关闭按钮或使用快捷键</li></ul><h3 id="窗口类型" tabindex="-1">窗口类型 <a class="header-anchor" href="#窗口类型" aria-label="Permalink to &quot;窗口类型&quot;">​</a></h3><p>RDE 支持三种窗口类型：</p><table tabindex="0"><thead><tr><th>类型</th><th>说明</th><th>适用场景</th></tr></thead><tbody><tr><td>组件窗口</td><td>Svelte 组件直接渲染</td><td>文件管理器、设置等原生应用</td></tr><tr><td>iframe 窗口</td><td>嵌入外部页面</td><td>Web 应用、第三方服务</td></tr><tr><td>弹窗</td><td>模态/非模态对话框</td><td>确认框、属性面板</td></tr></tbody></table><h3 id="多窗口管理" tabindex="-1">多窗口管理 <a class="header-anchor" href="#多窗口管理" aria-label="Permalink to &quot;多窗口管理&quot;">​</a></h3><ul><li>支持多窗口同时打开，自动管理层叠顺序（z-index）</li><li>点击窗口自动置顶</li><li>窗口间支持拖拽传递数据</li></ul><h2 id="任务栏" tabindex="-1">任务栏 <a class="header-anchor" href="#任务栏" aria-label="Permalink to &quot;任务栏&quot;">​</a></h2><p>屏幕底部的任务栏提供：</p><ul><li><strong>应用图标</strong>：常用应用快捷入口</li><li><strong>已打开窗口</strong>：点击切换或最小化/恢复窗口</li><li><strong>系统托盘</strong>：时间、通知、网络状态等</li><li><strong>开始菜单</strong>：所有已安装应用列表</li></ul><h2 id="右键菜单" tabindex="-1">右键菜单 <a class="header-anchor" href="#右键菜单" aria-label="Permalink to &quot;右键菜单&quot;">​</a></h2><p>桌面和文件管理器支持右键菜单操作，提供：</p><ul><li>新建文件/文件夹</li><li>粘贴、刷新</li><li>更换壁纸</li><li>显示设置</li></ul><h2 id="多用户支持" tabindex="-1">多用户支持 <a class="header-anchor" href="#多用户支持" aria-label="Permalink to &quot;多用户支持&quot;">​</a></h2><p>RDE 支持多用户并发使用：</p><ul><li>每个用户拥有独立的桌面空间</li><li>文件系统按用户隔离</li><li>终端会话按用户隔离</li><li>Linux 系统用户自动创建</li></ul><p>详见 <a href="/zh/docs/guide/users.html">用户管理</a>。</p>',21)])])}const g=a(r,[["render",o]]);export{p as __pageData,g as default};
